	    if (Ctrl('c_sexo').GetXValue() == "M")
	    	pblnMasculino = true;
	    else if (Ctrl('c_sexo').GetXValue() == "F") 
	    	pblnMasculino = false;
	    else return true;

	    var strSexoyDocumento;
	    var lngVerificador;

		var re = /-/g;
	    pstrCuil = pstrCuil.replace( re, "" );

	    if ( pstrCuil.length != 11 ) 
	   	{
	   		me.SetError('El largo del cuil es incorrecto');
	   		return false;
	   	}
		if ( !allDigits( pstrCuil ) ) 
		{
			me.SetError('El cuil tiene caracteres inválidos');
	   		return false;
		}

	    lngSexo = parseInt( pstrCuil.substr( 0, 2 ) );
	    strSexoyDocumento = pstrCuil.substr( 0, 10 );
	    lngVerificador = parseInt( pstrCuil.substr( pstrCuil.length - 1, 1 ) );

/*	    switch ( lngSexo )
