  function intDigVerificador( pstrCuil )
  {
    var dblSuma;
    var lngResto;
    var intDigVerificador;

    dblSuma = parseInt(pstrCuil.substr(0, 1)) * 5;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(1, 1)) * 4;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(2, 1)) * 3;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(3, 1)) * 2;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(4, 1)) * 7;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(5, 1)) * 6;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(6, 1)) * 5;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(7, 1)) * 4;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(8, 1)) * 3;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(9, 1)) * 2;

    lngResto = dblSuma % 11;
    if (lngResto == 0)
    {
    	return 0;
    }   
    else
    {
    	return parseInt(11 - lngResto);
    }
  }   

  function allDigits( str )
	{
		var justDigits=false;

		if(typeof str!='string') return false;
		if(str.length==0) return false;

		for( var i=0; i<str.length; i++ )
		{
			d=str.charAt(i)
			if ((d<'0') || (d>'9')) return false;
		}
		return true;
	}


function MarkAll()
{
	Ctrl("SELECT").DelAllRow();

	for (t=0; t<Ctrl("LIST").TotalRowsCount(); t++)
		Ctrl("SELECT").AddRow().SetAttr("id",Ctrl("LIST").GetAttrValue(t, "id"));

	Ctrl("LIST").Refresh();
}

function UnmarkAll()
{      
	Ctrl("SELECT").DelAllRow();
	Ctrl("LIST").Refresh();
}     

function EnableButtons()
{
	if (Ctrl("main").GetMode()=="PENDAPROB")
	{
		if (Ctrl("SELECT").CountRow()==0)
		{             
			CtrlEnabled("APROBAR",false);
		} else
		{
			CtrlEnabled("APROBAR",true);
		}
	}
}
